const payments = require('./payments/payment-provider');

function assertValoraAdmin(user) {
  if (user.role !== 'admin_valora') throw new HttpsError('permission-denied', 'Apenas Admin Valora pode operar cobrança.');
}

exports.createPaymentLink = onCall(async req => {
  const user = await authedUser(req); assertValoraAdmin(user);
  const invoiceId = required(req.data, 'invoiceId');
  const snap = await db.collection('invoices').doc(invoiceId).get();
  if (!snap.exists) throw new HttpsError('not-found', 'Fatura não encontrada.');
  const invoice = { id: snap.id, ...snap.data() };
  const provider = invoice.paymentProvider || 'manual';
  const result = await payments.createPaymentLink(invoice, provider);
  await snap.ref.set({ paymentProvider: provider, paymentUrl: result.paymentUrl || '', updatedAt: TS(), updatedBy: user.uid }, { merge: true });
  await auditLog(db, { action: 'payment_link_created', actorId: user.uid, actorType: user.role, companyId: invoice.companyId, entity: 'invoice', entityId: invoiceId, after: { provider } });
  return result;
});

exports.createCheckoutSession = onCall(async req => {
  const user = await authedUser(req); assertValoraAdmin(user);
  throw new HttpsError('failed-precondition', 'Checkout real ainda não configurado. Configure provider e secrets no backend.');
});
exports.syncSubscriptionStatus = onCall(async req => { const user = await authedUser(req); assertValoraAdmin(user); return { synced: false, mode: 'manual' }; });
exports.cancelSubscription = onCall(async req => { const user = await authedUser(req); assertValoraAdmin(user); return { cancelled: false, mode: 'manual' }; });
exports.upgradeSubscription = onCall(async req => { const user = await authedUser(req); assertValoraAdmin(user); return { upgraded: false, mode: 'manual' }; });
exports.downgradeSubscription = onCall(async req => { const user = await authedUser(req); assertValoraAdmin(user); return { downgraded: false, mode: 'manual' }; });

exports.handlePaymentWebhook = onCall(async req => {
  const provider = cleanText(req.data?.provider || 'manual', 40);
  if (provider !== 'manual') throw new HttpsError('failed-precondition', 'Webhooks reais devem usar endpoint HTTP com validação criptográfica de assinatura.');
  const result = await payments.handleWebhook({ ...req.data, provider }, provider, { db });
  await auditLog(db, { action: 'payment_webhook_received', actorType: 'system', entity: 'webhook', entityId: provider, after: result });
  return result;
});


// Integrações externas, API pública e webhooks corporativos.
const API_SCOPES=new Set(['employees:read','employees:write','surveys:read','responses:read','reports:read','webhooks:manage']);
function json(res,status,body){res.status(status).set('content-type','application/json').send(JSON.stringify(body));}
function publicError(res,status,code,message){return json(res,status,{error:{code,message}});}
function bearer(req){return String(req.headers.authorization||req.headers['x-api-key']||'').replace(/^Bearer\s+/i,'').trim();}
async function validateApiKeyRaw(req,scope){const key=bearer(req);if(!key)return null;const prefix=key.slice(0,12),hash=sha256(key);const qs=await db.collection('apiKeys').where('keyPrefix','==',prefix).where('status','==','active').limit(5).get();for(const d of qs.docs){const k={id:d.id,...d.data()};if(k.keyHash===hash&&(!k.expiresAt||Date.parse(k.expiresAt)>Date.now())&&(k.scopes||[]).includes(scope)){await d.ref.set({lastUsedAt:TS()},{merge:true});await rateLimit(`api:${k.companyId}:${prefix}`,120,60*1000);return k;}}return null;}
async function requireApi(req,res,scope){const k=await validateApiKeyRaw(req,scope);if(!k){publicError(res,401,'unauthorized','API key ausente, expirada, revogada ou sem escopo.');return null;}await auditLog(db,{action:'publicApi.call',actorType:'api_key',companyId:k.companyId,entity:'apiKey',entityId:k.id,after:{scope,path:req.path,method:req.method},ip:ip(req),userAgent:ua(req)});return k;}
async function listCollection(companyId,name,limit=200){const snap=await db.collection(name).where('companyId','==',companyId).limit(limit).get();return snap.docs.map(d=>({id:d.id,...d.data()}));}
exports.createApiKey=onCall(async req=>{const user=await authedUser(req), data=asObject(req.data,'payload');const companyId=user.role==='admin_valora'?cleanText(data.companyId,120):user.companyId;if(!companyId||!['admin_valora','empresa_admin'].includes(user.role))throw new HttpsError('permission-denied','Sem permissão para criar chave.');const scopes=(Array.isArray(data.scopes)?data.scopes:[]).filter(s=>API_SCOPES.has(s));if(!scopes.length)throw new HttpsError('invalid-argument','Informe ao menos um escopo.');const secret=`vp_live_${createToken(32)}`, ref=db.collection('apiKeys').doc();await ref.set({id:ref.id,companyId,name:cleanText(data.name||'API Key',120),keyHash:sha256(secret),keyPrefix:secret.slice(0,12),scopes,status:'active',lastUsedAt:null,expiresAt:cleanText(data.expiresAt||'',60)||null,createdAt:TS(),createdBy:user.uid});await auditLog(db,{action:'api_key.created',actorId:user.uid,actorType:user.role,companyId,entity:'apiKey',entityId:ref.id,after:{keyPrefix:secret.slice(0,12),scopes}});return {id:ref.id,key:secret,keyPrefix:secret.slice(0,12),scopes};});
exports.revokeApiKey=onCall(async req=>{const user=await authedUser(req), id=required(req.data,'id');const ref=db.collection('apiKeys').doc(id), snap=await ref.get();if(!snap.exists)throw new HttpsError('not-found','Chave não encontrada.');const k=snap.data();if(user.role!=='admin_valora'&&k.companyId!==user.companyId)throw new HttpsError('permission-denied','Chave fora da sua empresa.');await ref.set({status:'revoked',revokedAt:TS(),revokedBy:user.uid},{merge:true});await auditLog(db,{action:'api_key.revoked',actorId:user.uid,actorType:user.role,companyId:k.companyId,entity:'apiKey',entityId:id});return {revoked:true};});
exports.validateApiKey=onCall(async req=>{const key=required(req.data,'key'),scope=required(req.data,'scope');const fakeReq={headers:{authorization:`Bearer ${key}`},rawRequest:{headers:{},ip:''}};const found=await validateApiKeyRaw(fakeReq,scope);return found?{valid:true,companyId:found.companyId,scopes:found.scopes}:{valid:false};});
exports.publicApi=onRequest(async(req,res)=>{try{const path=String(req.path||req.url||'').replace(/\?.*$/,'');if(req.method==='OPTIONS'){res.set('access-control-allow-origin','*').set('access-control-allow-headers','authorization,x-api-key,content-type').set('access-control-allow-methods','GET,POST,PUT,OPTIONS').status(204).send('');return;}let key;if(path==='/api/v1/employees'&&req.method==='GET'){key=await requireApi(req,res,'employees:read');if(!key)return;return json(res,200,{data:await listCollection(key.companyId,'users')});}if(path==='/api/v1/employees'&&req.method==='POST'){key=await requireApi(req,res,'employees:write');if(!key)return;const body=asObject(req.body||{},'body');const ref=db.collection('users').doc();await ref.set({id:ref.id,companyId:key.companyId,name:cleanText(body.name,160),email:cleanText(body.email,254).toLowerCase(),phone:cleanText(body.phone,60),position:cleanText(body.position,120),department:cleanText(body.department,120),role:['participante','gestor_pesquisa','analista_resultados','gestor_area'].includes(body.role)?body.role:'participante',status:body.status||'active',receivesEmail:body.receivesEmail!==false,portalAccess:body.portalAccess===true,createdAt:TS(),createdBy:'api'});return json(res,201,{data:{id:ref.id}});}const emp=path.match(/^\/api\/v1\/employees\/([^/]+)$/);if(emp&&req.method==='PUT'){key=await requireApi(req,res,'employees:write');if(!key)return;const ref=db.collection('users').doc(emp[1]), snap=await ref.get();if(!snap.exists||snap.data().companyId!==key.companyId)return publicError(res,404,'not_found','Funcionário não encontrado.');const body=asObject(req.body||{},'body');const patch={companyId:key.companyId,updatedAt:TS(),updatedBy:'api'};['name','phone','position','department','status','receivesEmail','portalAccess'].forEach(f=>{if(Object.prototype.hasOwnProperty.call(body,f))patch[f]=typeof body[f]==='string'?cleanText(body[f],180):body[f];});if(Object.prototype.hasOwnProperty.call(body,'role'))patch.role=['participante','gestor_pesquisa','analista_resultados','gestor_area'].includes(body.role)?body.role:'participante';if(Object.prototype.hasOwnProperty.call(body,'email')){const email=cleanText(body.email,254).toLowerCase();if(!EMAIL_RE.test(email))return publicError(res,400,'invalid_payload','E-mail inválido.');patch.email=email;}await ref.set(patch,{merge:true});return json(res,200,{data:{id:emp[1],updated:true}});}if(path==='/api/v1/surveys'&&req.method==='GET'){key=await requireApi(req,res,'surveys:read');if(!key)return;return json(res,200,{data:await listCollection(key.companyId,'surveys')});}if(path==='/api/v1/responses'&&req.method==='GET'){key=await requireApi(req,res,'responses:read');if(!key)return;const rows=(await listCollection(key.companyId,'responses')).map(r=>r.anonymous?{...r,participant:{email:'anonimizado',name:'anonimizado'}}:r);return json(res,200,{data:rows});}if(path==='/api/v1/reports'&&req.method==='GET'){key=await requireApi(req,res,'reports:read');if(!key)return;return json(res,200,{data:{companyId:key.companyId,responses:(await listCollection(key.companyId,'responses')).length,surveys:(await listCollection(key.companyId,'surveys')).length}});}if(path==='/api/v1/webhooks/test'&&req.method==='POST'){key=await requireApi(req,res,'webhooks:manage');if(!key)return;return json(res,200,{data:{queued:true,event:'webhook.test'}});}return publicError(res,404,'not_found','Endpoint não encontrado.');}catch(err){console.error(err);return publicError(res,500,'internal',err.message||'Erro interno.');}});
async function deliverWebhook(webhook,event,payload){const webhookUrl=assertWebhookUrl(webhook.url);const body=JSON.stringify({eventId:createToken(16),event,createdAt:new Date().toISOString(),data:payload});const timestamp=String(Date.now()), signature='sha256='+sha256(`${timestamp}.${body}.${webhook.secretHash||''}`);try{const r=await fetch(webhookUrl,{method:'POST',headers:{'content-type':'application/json','X-Valora-Event':event,'X-Valora-Timestamp':timestamp,'X-Valora-Signature':signature},body});await db.collection('webhooks').doc(webhook.id).set({lastDeliveryAt:TS(),lastDeliveryStatus:r.ok?'success':'failed',failureCount:admin.firestore.FieldValue.increment(r.ok?0:1)},{merge:true});await db.collection('integrationLogs').add({companyId:webhook.companyId,integrationId:webhook.id,type:'webhook',action:r.ok?'webhook.sent':'webhook.failed',status:r.ok?'success':'error',requestSummary:event,responseSummary:String(r.status),createdAt:TS()});return {ok:r.ok,status:r.status};}catch(e){await db.collection('webhooks').doc(webhook.id).set({lastDeliveryAt:TS(),lastDeliveryStatus:'failed',failureCount:admin.firestore.FieldValue.increment(1)},{merge:true});return {ok:false,error:e.message};}}
exports.dispatchWebhook=onCall(async req=>{const user=await authedUser(req), event=required(req.data,'event'), payload=asObject(req.data.payload||{},'payload'), companyId=user.role==='admin_valora'?cleanText(req.data.companyId,120):user.companyId;const snap=await db.collection('webhooks').where('companyId','==',companyId).where('status','==','active').get();const out=[];for(const d of snap.docs){const w={id:d.id,...d.data()};if((w.events||[]).includes(event))out.push(await deliverWebhook(w,event,payload));}return {delivered:out.length,items:out};});
exports.testWebhook=onCall(async req=>{const user=await authedUser(req), id=required(req.data,'id');const snap=await db.collection('webhooks').doc(id).get();if(!snap.exists)throw new HttpsError('not-found','Webhook não encontrado.');const w={id:snap.id,...snap.data()};if(user.role!=='admin_valora'&&w.companyId!==user.companyId)throw new HttpsError('permission-denied','Webhook fora da sua empresa.');return deliverWebhook(w,'webhook.test',{ok:true,lgpd:'payload mínimo de teste'});});
exports.importEmployees=onCall(async req=>{const user=await authedUser(req), rows=Array.isArray(req.data.rows)?req.data.rows:[], companyId=user.role==='admin_valora'?cleanText(req.data.companyId,120):user.companyId;if(!['admin_valora','empresa_admin'].includes(user.role))throw new HttpsError('permission-denied','Sem permissão para importar.');let created=0,updated=0,errors=[];for(const row of rows){const email=cleanText(row.email,254).toLowerCase();if(!EMAIL_RE.test(email)){errors.push({email,error:'invalid_email'});continue;}if(['admin_valora','consultor_valora'].includes(row.role)){errors.push({email,error:'global_role_forbidden'});continue;}const existing=await db.collection('users').where('companyId','==',companyId).where('email','==',email).limit(1).get();const payload={companyId,name:cleanText(row.name,160),email,phone:cleanText(row.phone,60),position:cleanText(row.position,120),department:cleanText(row.department,120),role:cleanText(row.role||'participante',40),status:row.status||'active',receivesEmail:row.receivesEmail!==false,portalAccess:row.portalAccess===true,updatedAt:TS()};if(existing.empty){const ref=db.collection('users').doc();await ref.set({...payload,id:ref.id,createdAt:TS(),createdBy:user.uid});created++;}else{await existing.docs[0].ref.set(payload,{merge:true});updated++;}}await auditLog(db,{action:'employees.imported',actorId:user.uid,actorType:user.role,companyId,entity:'integration',after:{created,updated,errors:errors.length}});return {total:rows.length,created,updated,ignored:0,errors};});
exports.exportData=onCall(async req=>{const user=await authedUser(req), type=cleanText(req.data.type,80), filters=asObject(req.data.filters||{},'filters'), companyId=user.role==='admin_valora'?cleanText(filters.companyId,120):user.companyId;if(!['admin_valora','empresa_admin','gestor_pesquisa','analista_resultados'].includes(user.role))throw new HttpsError('permission-denied','Sem permissão para exportar.');const collection=type==='employees'?'users':type.startsWith('responses')?'responses':type==='surveys'?'surveys':'responses';let rows=await listCollection(companyId,collection,1000);if(type==='employees')rows=rows.map(({password,...r})=>r);if(type==='responses_flat')rows=rows.map(r=>({companyId,surveyId:r.surveyId,responseId:r.id,participantEmail:r.anonymous?'anonimizado':r.participant?.email||'',department:r.department||r.participant?.department||'',createdAt:r.createdAt,normalized5:r.normalized5,percentage:r.percentage,level:r.level?.label||''}));await auditLog(db,{action:'data.exported',actorId:user.uid,actorType:user.role,companyId,entity:'integration',after:{type,count:rows.length}});return {type,count:rows.length,rows};});

function publicSupportPayload(req){const body=req.body||{};return {name:cleanText(body.name,120),email:cleanText(body.email,180),subject:cleanText(body.subject||'Atendimento público',160),message:cleanText(body.message,2000),companyId:cleanText(body.companyId||'',160),metadata:{route:cleanText(body.route||'',300),origin:'public_api'}};}
exports.createPublicSupportConversation=onRequest({cors:true},async (req,res)=>{try{if(req.method!=='POST')return res.status(405).json({error:'method_not_allowed'});await rateLimit(`publicSupport:${ip({rawRequest:req})||'unknown'}`,5,15*60*1000);const p=publicSupportPayload(req);if(!p.name||!EMAIL_RE.test(p.email)||!p.message)return res.status(400).json({error:'invalid_payload'});const ref=db.collection('supportConversations').doc();await ref.set({id:ref.id,companyId:p.companyId,origin:'public',status:'waiting_agent',priority:'normal',subject:p.subject,requesterName:p.name,requesterEmail:maskEmail(p.email),requesterUserId:'',requesterRole:'public',assignedToUserId:'',assignedToName:'',assignedToRole:'',channel:'web',createdAt:TS(),updatedAt:TS(),lastMessageAt:TS(),unreadForRequester:0,unreadForAgent:1,metadata:p.metadata});await ref.collection('messages').add({conversationId:ref.id,companyId:p.companyId,senderType:'requester',senderUserId:'',senderName:p.name,senderRole:'public',message:p.message,attachments:[],internal:false,createdAt:TS(),readAt:null});await logServerEvent(db,admin,{level:'info',category:'support_chat',action:'public_conversation_created',message:'Atendimento público criado via Cloud Function.',companyId:p.companyId,metadata:{conversationId:ref.id,subject:p.subject,email:maskEmail(p.email)}});return res.json({ok:true,conversationId:ref.id});}catch(err){console.error(err);return res.status(err.code==='resource-exhausted'?429:500).json({error:'support_unavailable'});}});
exports.sendPublicSupportMessage=onRequest({cors:true},async (req,res)=>{try{if(req.method!=='POST')return res.status(405).json({error:'method_not_allowed'});await rateLimit(`publicSupportMsg:${ip({rawRequest:req})||'unknown'}`,20,15*60*1000);const conversationId=cleanText(req.body?.conversationId,160),message=cleanText(req.body?.message,2000),name=cleanText(req.body?.name||'Visitante',120);if(!conversationId||!message)return res.status(400).json({error:'invalid_payload'});const ref=db.collection('supportConversations').doc(conversationId),snap=await ref.get();if(!snap.exists||snap.data().origin!=='public')return res.status(404).json({error:'not_found'});await ref.collection('messages').add({conversationId,companyId:snap.data().companyId||'',senderType:'requester',senderUserId:'',senderName:name,senderRole:'public',message,attachments:[],internal:false,createdAt:TS(),readAt:null});await ref.set({status:'waiting_agent',updatedAt:TS(),lastMessageAt:TS(),unreadForAgent:admin.firestore.FieldValue.increment(1)},{merge:true});return res.json({ok:true});}catch(err){console.error(err);return res.status(err.code==='resource-exhausted'?429:500).json({error:'support_unavailable'});}});

const SUPPORT_PRIORITIES=new Set(['low','medium','high','critical']);
const SUPPORT_STATUSES=new Set(['open','waiting_agent','waiting_user','in_progress','resolved','closed','cancelled','transferred']);
function supportSlaDue(priority='medium'){const hours=priority==='critical'?8:priority==='high'?24:priority==='low'?72:48;return admin.firestore.Timestamp.fromMillis(Date.now()+hours*3600000);}
async function supportUser(req){return authedUser(req);}
async function writeSupportAudit(action,ticket,metadata={}){return logServerEvent(db,admin,{level:'info',category:'support_chat',action,message:`Suporte: ${action}.`,companyId:ticket.companyId||'',metadata:{ticketId:ticket.id||'',...metadata}});}
function cleanSupportPayload(data={}){return {name:cleanText(data.name||data.requesterName||'',120),email:cleanText(data.email||data.requesterEmail||'',254).toLowerCase(),subject:cleanText(data.subject||'Atendimento',180),message:cleanText(data.message||data.description||'',2000),companyId:cleanText(data.companyId||'',160),companyName:cleanText(data.companyName||'',180),category:cleanText(data.category||'outros',80),priority:SUPPORT_PRIORITIES.has(data.priority)?data.priority:'medium',origin:cleanText(data.origin||'portal',80),channel:cleanText(data.channel||'web',60),relatedSurveyId:cleanText(data.relatedSurveyId||'',160),relatedResponseId:cleanText(data.relatedResponseId||'',160),relatedRoute:cleanText(data.relatedRoute||'',300)};}
exports.createPublicSupportTicket=onCall(async req=>{await rateLimit(`supportPublic:${ip(req)||'unknown'}`,5,15*60*1000);const p=cleanSupportPayload(req.data||{});if(!p.name||!EMAIL_RE.test(p.email)||!p.message)throw new HttpsError('invalid-argument','Nome, e-mail e mensagem são obrigatórios.');const ref=db.collection('supportTickets').doc();const ticket={id:ref.id,companyId:p.companyId,companyName:p.companyName,requesterUserId:'',requesterName:p.name,requesterEmail:maskEmail(p.email),requesterRole:'public',requesterType:'public',assignedToUserId:'',assignedToName:'',assignedToRole:'',subject:p.subject,description:p.message,category:p.category,priority:p.category==='erro_tecnico'?'high':p.priority,status:'waiting_agent',origin:p.origin||'portal',channel:p.channel,relatedEntity:p.relatedSurveyId?'survey':'',relatedEntityId:p.relatedSurveyId||'',relatedSurveyId:p.relatedSurveyId,relatedResponseId:p.relatedResponseId,relatedRoute:p.relatedRoute,slaPolicyId:`sla_${p.priority}`,slaDueAt:supportSlaDue(p.priority),firstResponseAt:null,resolvedAt:null,closedAt:null,unreadForRequester:0,unreadForAgent:1,rating:null,ratingComment:'',createdAt:TS(),updatedAt:TS(),createdBy:'public',updatedBy:'public'};await ref.set(ticket);await ref.collection('messages').add({id:'',ticketId:ref.id,companyId:p.companyId,senderType:'requester',senderUserId:'',senderName:p.name,senderRole:'public',message:p.message,internal:false,attachments:[],createdAt:TS(),readAt:null});await writeSupportAudit('ticket_created',ticket,{origin:p.origin,email:maskEmail(p.email)});return {ok:true,ticketId:ref.id};});
exports.sendSupportMessage=onCall(async req=>{const user=await supportUser(req), ticketId=required(req.data,'ticketId'), message=cleanText(req.data.message||'',2000), internal=asBoolean(req.data.internal);if(!message)throw new HttpsError('invalid-argument','Mensagem obrigatória.');const ref=db.collection('supportTickets').doc(ticketId), snap=await ref.get();if(!snap.exists)throw new HttpsError('not-found','Ticket não encontrado.');const t={id:snap.id,...snap.data()};const isAgent=['admin_valora','consultor_valora','empresa_admin'].includes(user.role)||user.canHandleSupport;if(user.role!=='admin_valora'&&user.role!=='consultor_valora'&&t.companyId!==user.companyId&&t.requesterUserId!==user.uid)throw new HttpsError('permission-denied','Ticket fora do seu escopo.');if(internal&&!isAgent)throw new HttpsError('permission-denied','Notas internas são restritas a atendentes.');await ref.collection('messages').add({ticketId,companyId:t.companyId,senderType:isAgent?'agent':'requester',senderUserId:user.uid,senderName:user.name||user.email,senderRole:user.role,message,internal,attachments:[],createdAt:TS(),readAt:null});const patch={updatedAt:TS(),unreadForRequester:isAgent?1:(t.unreadForRequester||0),unreadForAgent:isAgent?(t.unreadForAgent||0):1};if(isAgent&&!t.firstResponseAt)patch.firstResponseAt=TS();if(!internal)patch.status=isAgent?'waiting_user':'waiting_agent';await ref.set(patch,{merge:true});await writeSupportAudit(internal?'internal_note_added':'message_sent',t,{senderRole:user.role});return {ok:true};});
exports.assignSupportTicket=onCall(async req=>{const user=await supportUser(req), ticketId=required(req.data,'ticketId');const ref=db.collection('supportTickets').doc(ticketId), snap=await ref.get();if(!snap.exists)throw new HttpsError('not-found','Ticket não encontrado.');const t={id:snap.id,...snap.data()};if(!['admin_valora','consultor_valora','empresa_admin'].includes(user.role))throw new HttpsError('permission-denied','Sem permissão.');if(!['admin_valora','consultor_valora'].includes(user.role)&&t.companyId!==user.companyId)throw new HttpsError('permission-denied','Ticket fora da empresa.');await ref.set({assignedToUserId:user.uid,assignedToName:user.name||user.email,assignedToRole:user.role,status:'in_progress',updatedAt:TS(),updatedBy:user.uid},{merge:true});await writeSupportAudit('ticket_assigned',t,{agent:user.uid});return {ok:true};});
exports.closeSupportTicket=onCall(async req=>{const user=await supportUser(req), ticketId=required(req.data,'ticketId'), status=SUPPORT_STATUSES.has(req.data.status)?req.data.status:'closed';const ref=db.collection('supportTickets').doc(ticketId), snap=await ref.get();if(!snap.exists)throw new HttpsError('not-found','Ticket não encontrado.');const t={id:snap.id,...snap.data()};if(user.role!=='admin_valora'&&t.companyId!==user.companyId&&t.requesterUserId!==user.uid)throw new HttpsError('permission-denied','Ticket fora do seu escopo.');await ref.set({status,closedAt:status==='closed'?TS():t.closedAt||null,resolvedAt:status==='resolved'?TS():t.resolvedAt||null,updatedAt:TS(),updatedBy:user.uid},{merge:true});await writeSupportAudit('ticket_closed',t,{status});return {ok:true};});
exports.notifySupportTicket=onCall(async req=>{const user=await supportUser(req);if(!['admin_valora','consultor_valora'].includes(user.role))throw new HttpsError('permission-denied','Sem permissão.');const ticketId=required(req.data,'ticketId'), snap=await db.collection('supportTickets').doc(ticketId).get();if(!snap.exists)throw new HttpsError('not-found','Ticket não encontrado.');const t={id:snap.id,...snap.data()};await logServerEvent(db,admin,{level:t.priority==='critical'?'critical':'info',category:'telegram',action:'support_ticket_alert',message:`Novo ticket ${t.priority}: ${t.subject}`,companyId:t.companyId,metadata:{ticketId:t.id,companyName:t.companyName,category:t.category,priority:t.priority,origin:t.origin}});return {ok:true};});
exports.checkSupportSla=onSchedule('every 15 minutes',async()=>{const now=admin.firestore.Timestamp.now();const snap=await db.collection('supportTickets').where('status','in',['open','waiting_agent','waiting_user','in_progress']).where('slaDueAt','<=',now).limit(100).get();for(const doc of snap.docs){const t={id:doc.id,...doc.data()};await writeSupportAudit('sla_overdue',t,{slaDueAt:t.slaDueAt});await doc.ref.set({slaOverdue:true,updatedAt:TS()},{merge:true});}return null;});
